class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<int> earliest(n, INT_MAX);
        earliest[0] = 0;
        earliest[firstPerson] = 0;

        unordered_map<int, vector<pair<int,int>>> timeGraph;
        for (auto& m : meetings) {
            int x = m[0], y = m[1], t = m[2];
            timeGraph[t].emplace_back(x, y);
        }

        vector<int> times;
        for (auto& [t, _] : timeGraph) times.push_back(t);
        sort(times.begin(), times.end());

        for (int t : times) {
            unordered_map<int, vector<int>> g;
            unordered_set<int> nodes;
            for (auto [x, y] : timeGraph[t]) {
                g[x].push_back(y);
                g[y].push_back(x);
                nodes.insert(x);
                nodes.insert(y);
            }

            queue<int> q;
            for (int v : nodes) {
                if (earliest[v] <= t) {
                    q.push(v);
                }
            }

            while (!q.empty()) {
                int u = q.front(); q.pop();
                for (int v : g[u]) {
                    if (earliest[v] > t) {
                        earliest[v] = t;
                        q.push(v);
                    }
                }
            }
        }

        vector<int> res;
        for (int i = 0; i < n; ++i) {
            if (earliest[i] != INT_MAX) res.push_back(i);
        }
        return res;
    }
};
